var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"아이들을 데리고 온 뒤 작동을 멈췄어. 상태는 어때 보여?","JPN":"子供たちを連れ帰った後、動かなくなったよ。どういう状態かしら？","ENG":"It stopped working after it came back with the children. What do you think is the problem?","TWN":"它將孩子們帶回來後便停止運作，看起來情況如何？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"파손된 곳은 없다. 단순히 동력이 부족해서 멈춘 것 같군.","JPN":"壊れたところはない。単に動力不足で止まったようだな。","ENG":"Nothing’s been damaged. Maybe it stopped working simply because it needs power.","TWN":"沒有毀損的地方，應該只是單純動力不足。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"다시 움직이게 하려면 병기마의 사양에 맞는 강력한 동력원이 필요해.","JPN":"また動かすためには、兵器馬の仕様に合う強力な動力源が必要だ。","ENG":"To get it started again I’ll need a powerful generator that fits the Armored Horse's specifications.","TWN":"想讓它再次動起來的話，需要符合戰馬規格的強大動能。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"수송 차량에 쓰는 예비용 배터리가 있어. 그걸로 동력을 공급해 볼 수 없을까?","JPN":"輸送車両に使う予備用のバッテリーがあるけど、それで動力を供給することはできない？","ENG":"There's a spare battery left for the transport vehicle. Will that be enough power it?","TWN":"有運輸車輛的備用電池，可以用那個來提供動力嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"유감이지만 자동차 배터리로 병기마를 움직일 수는 없어.","JPN":"残念だが、自動車のバッテリーで兵器馬を動かすことはできない。","ENG":"I'm afraid not. A car battery’s not enough to move an Armored Horse.","TWN":"很遺憾，汽車電池是無法讓戰馬動起來的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"흐음… 원인을 알고 있다니 다행이네.","JPN":"ふうん……原因がわかるならよかった。","ENG":"Hmm... I'm relieved you know what the cause is.","TWN":"嗯嗯……幸好你還知道原因。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"무슨 뜻이지?","JPN":"どういうことだ？","ENG":"What's that supposed to mean?","TWN":"什麼意思？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"자기가 타고 다니던 병기마에 대한 지식은 잊지 않은 것 같아서 말이야.","JPN":"自分が乗っていた兵器馬についての知識は忘れてないみたいだから。","ENG":"That you haven't forgotten anything about the Armored Horse you came here on.","TWN":"就是你沒有忘記關於你騎過的戰馬的知識。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당신이 병기마를 어딘가에서 훔쳤을 뿐이라면, 방금처럼 보자마자 판단하진 못했을 테니까.","JPN":"どこかで兵器馬を盗んだだけなら、今のように見てすぐ判断できなかっただろうね。","ENG":"If you had stolen it from somewhere, you wouldn't be able to know the cause, right?","TWN":"如果戰馬是你不知道從哪偷來的，那你應該就不會說出剛才那番話。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"아직도 의심 받고 있었나? 유감이군.","JPN":"まだ疑っていたのか？　残念だな。","ENG":"Are you still doubting me? Ugh..","TWN":"你還在懷疑我嗎？真是遺憾。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"미안. 대신 저녁으로 감자 요리 대접할게.","JPN":"ごめん。その代わり、夕飯はジャガイモの料理をごちそうするから。","ENG":"Sorry. I'll treat you to some potatoes for dinner.","TWN":"抱歉，晚上請你吃馬鈴薯料理以表歉意吧。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하지만 그 전에, 먼저 만나 봐야 할 친구들이 있어.","JPN":"でもその前に、あの子たちに会わないとね。","ENG":"But before we do that I need to see some friends of mine.","TWN":"不過在那之前，你得先見一些人。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"친구들?","JPN":"あの子たち？","ENG":"\\"Friends\\"?","TWN":"見誰？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"고철 수집이라고?","JPN":"鉄くず拾い？","ENG":"Gathering scrap metal you say?","TWN":"收集廢鐵？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NOMAD_BORDER_A_KID","text":{"KOREA":"네. 외성 밖을 돌아다니다 보면 쓸 만한 골동품을 찾을 수 있거든요.","JPN":"うん。外郭の外を歩いてると、使えそうな骨董品が見つかるんだ。","ENG":"Uh-huh. There are a lot of valuable antiques outside the castle.","TWN":"對，在外城外繞繞的話，應該可以找到還能用的古董。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NOMAD_BORDER_A_KID","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"하지만 아이들끼리 침식지대로 나가는 건 위험하진 않나?","JPN":"でも子供たちだけで侵食地帯に出るのは危ないはずでは？","ENG":"But isn't it dangerous for children to be out there in the Corrupted Areas?","TWN":"但是小朋友去侵蝕地帶不會有危險嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NOMAD_BORDER_B_KID","text":{"KOREA":"너무 멀리 나가지만 않으면 괜찮댔어요! 좋은 고철을 찾으면 돈도 많이 벌고요!","JPN":"あまり遠くまで行かなければ大丈夫なんだって！　いい鉄くずを見つけたらお金もいっぱいもらえるし！","ENG":"They said it was okay as long as we don't stray too far! And we can make money if we find something good!","TWN":"只要不走太遠就好啦！找到好的廢鐵可以賺很多錢喔！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NOMAD_BORDER_C_KID","face":"UNIT_IDLE"},"C":{"char_id":"NOMAD_BORDER_B_KID","face":"UNIT_IDLE"},"R":{"char_id":"NOMAD_BORDER_A_KID","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"NOMAD_BORDER_C_KID","text":{"KOREA":"도시 어른들은 저희가 침식 환자라고 일을 안 시켜 줘요.","JPN":"都市の大人たちは僕らが侵食患者だからって仕事をくれないんです。","ENG":"The people in the city don't give us any work because we're affected by the Corruption.","TWN":"城裡的大人都說我們是侵蝕患者，根本不給我們事做。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NOMAD_BORDER_C_KID","face":"UNIT_IDLE"},"C":{"char_id":"NOMAD_BORDER_B_KID","face":"UNIT_IDLE"},"R":{"char_id":"NOMAD_BORDER_A_KID","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"NOMAD_BORDER_A_KID","text":{"KOREA":"그래서 어제도 고철을 모으러 갔는데… 좀 멀리 갔다가 침식체를 만난 거예요.","JPN":"それで昨日も鉄くずを探しに行ったんだけど……ちょっと遠くに行きすぎて侵食体と出くわしちゃったんだ。","ENG":"So that's why we were out there yesterday... But we went too far and met a C.O.","TWN":"我們昨天也是去收集廢鐵…只是跑得比較遠，結果遇到侵蝕體。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NOMAD_BORDER_C_KID","face":"UNIT_IDLE"},"C":{"char_id":"NOMAD_BORDER_B_KID","face":"UNIT_IDLE"},"R":{"char_id":"NOMAD_BORDER_A_KID","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NOMAD_BORDER_B_KID","text":{"KOREA":"아저씨가 와 줘서 살았어요!","JPN":"おじさんが来てくれて助かったわ！","ENG":"But you saved us, Mister!","TWN":"因爲大叔出現我們才能活命！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NOMAD_BORDER_C_KID","face":"UNIT_IDLE"},"C":{"char_id":"NOMAD_BORDER_B_KID","face":"UNIT_IDLE"},"R":{"char_id":"NOMAD_BORDER_A_KID","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"NOMAD_BORDER_C_KID","text":{"KOREA":"침식체한테 맨주먹으로 덤빌 때는 죽는 줄 알았지만요.","JPN":"侵食体に素手で飛びかかった時には死ぬかと思いましたけど。","ENG":"Even though we thought we were goners when you tried to punch it...","TWN":"當你赤手空拳衝向侵蝕體時，我還以為你會死掉欸！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NOMAD_BORDER_C_KID","face":"UNIT_IDLE"},"C":{"char_id":"NOMAD_BORDER_B_KID","face":"UNIT_IDLE"},"R":{"char_id":"NOMAD_BORDER_A_KID","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"크흠. 그건 잊어 버려도 돼.","JPN":"コホン。それは忘れていいんだ。","ENG":"Ahem... Please forget about that.","TWN":"咳咳，這件事可以忘掉沒關係。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NOMAD_BORDER_A_KID","text":{"KOREA":"아무튼 침식체한테 쫓기기 전에 커다란 고철배를 발견했거든요?","JPN":"とにかく、侵食体に追われる前に、ぼろい船を発見したんだ。","ENG":"Anyway, we found this huge ship just before they started chasing us!","TWN":"總之侵蝕體出現之前，我們發現一艘巨大的廢鐵船。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NOMAD_BORDER_C_KID","face":"UNIT_IDLE"},"C":{"char_id":"NOMAD_BORDER_B_KID","face":"UNIT_IDLE"},"R":{"char_id":"NOMAD_BORDER_A_KID","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"NOMAD_BORDER_C_KID","text":{"KOREA":"아직 거기 있을 거예요. 우리끼리는 못 옮길 만큼 엄청 컸어요.","JPN":"まだそこにあるはずです。僕らだけでは運べないくらい大きな船でした。","ENG":"I'm sure it's still here. It was so big we couldn't move it ourselves.","TWN":"它應該還在那裡，超大艘的，大到我們根本搬不動。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NOMAD_BORDER_C_KID","face":"UNIT_IDLE"},"C":{"char_id":"NOMAD_BORDER_B_KID","face":"UNIT_IDLE"},"R":{"char_id":"NOMAD_BORDER_A_KID","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"NOMAD_BORDER_B_KID","text":{"KOREA":"저희 집보다요! 게다가 엄청 신기하게 생겼어요!","JPN":"私の家より大きかったよ！　それにすごく不思議な形をしてたの！","ENG":"It was bigger than our house! And it didn't look like anything I've seen before!","TWN":"比我家還大喔！而且長得很特別！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NOMAD_BORDER_C_KID","face":"UNIT_IDLE"},"C":{"char_id":"NOMAD_BORDER_B_KID","face":"UNIT_IDLE"},"R":{"char_id":"NOMAD_BORDER_A_KID","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"고철배라고? 이 근처에 그런 배를 띄울 호수가 있었나?","JPN":"ぼろい船だと？　この辺りにそういう船を浮かべる湖があるのか？","ENG":"A ship? Is there any lake nearby for a ship like that?","TWN":"廢鐵船？這附近有可以停泊那種船的湖嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"차원 함선을 말하는 거야. 관리국이 지원하는 기술로 만들어진 대형 선박이지.","JPN":"次元艦船のことだと思うよ。管理局が支援する技術で作られた大型の船舶。","ENG":"They're talking about a dimensional ship. It's a large vessel built with technology provided by the Administration.","TWN":"他們說的是次元艦船，那是由管理局支援的技術製造而成的大型船隻。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"바깥 세상에서는 그걸 타고 이면세계로 넘어간다고 해.","JPN":"外の世界ではそれに乗って裏世界に行くらしい。","ENG":"It's said that people use it to cross into Counterside.","TWN":"據說可以搭乘它進入異界。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"이면세계?","JPN":"裏世界？","ENG":"\\"Counterside\\"?","TWN":"異界？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당신도 익숙할 거야. 침식의 날에 침식체를 쏟아냈던 균열 저편의 세계거든.","JPN":"あなたもよく知っているはずよ。侵食の日に侵食体が溢れ出た亀裂のむこうの世界なんだ。","ENG":"You should be familiar with it. It's the world beyond the rift that the C.O.s flooded out of on the Day of Corruption.","TWN":"你應該也會知道，就是在侵蝕之日，侵蝕體湧出的裂縫那端的世界。  "},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"낙원문이 이면세계의 통로를 잠그는 자물쇠라면, 차원 함선은 통로를 여는 열쇠인 셈이지.","JPN":"楽園の門が裏世界への通路を閉ざす錠だとしたら、次元艦船は通路を開ける鍵というわけ。","ENG":"If Avalon's Gate is the key locking the path to Counterside, the dimensional ship is the key that opens it.","TWN":"若樂園門是封鎖異界通道的鎖，那次元艦船就是打開通道的鑰匙。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"왜 그런 엄청난 물건이 외성 밖에 방치되어 있는 거지?","JPN":"そんなすごいものがなぜ外郭の外に放置されているんだ？","ENG":"Then why is a powerful ship like that abandoned outside the castle?","TWN":"爲什麼那麼大的東西被擱置在外城外？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"글쎄. 어쩌면 관리국에서 로스트 쉽이라고 부르는 물건일지도.","JPN":"さあ？　もしかしたら管理局でロストシップと呼ばれてるものなのかも。","ENG":"I don't know. Maybe it's what the Administration calls the \\"Lost Ship\\".","TWN":"不清楚，也許它就是管理局所說的失落艦船。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하지만 지금 분명한 사실은 우리가 그 고철배를 이용할 수 있다는 거야.","JPN":"確かなことは、私たちがそのぼろい鉄船を利用できるということ。","ENG":"However, what I know for certain is that we can salvage the ship.","TWN":"但現在可以確定的，就是我們可以利用那個廢鐵。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"차원 함선을 고쳐 쓰자는 말인가?","JPN":"次元艦船を修理して使おうと？","ENG":"Are you talking about fixing the dimensional ship?","TWN":"意思是要修理次元艦船嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"미안하지만, 나도 내가 모르는 물건을 고칠 수 있을지는 장담 못해.","JPN":"すまないが、私も知らないものを直せるかどうかは断言できないな。","ENG":"Look, I can't guarantee I can fix something I know nothing about.","TWN":"很抱歉，我無法保證能修好我沒碰過的東西。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"잘못 짚었어. 여길 지키기도 벅찬데 자진해서 이면세계에 뛰어들 이유도 없잖아.","JPN":"見当外れ。ここを守るので精一杯なのに、進んで裏世界に飛び込む理由がないでしょ？","ENG":"You got it wrong. It's difficult enough defending against C.O.s here. There's no reason for us to voluntarily enter Counterside.","TWN":"答錯，光是保護這裡就已經夠累人的，有什麼理由跳進異界裡呢？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"하지만 함선의 코어가 아직 멀쩡하다면, 써먹어 볼 수는 있겠지.","JPN":"でも艦船のコアにまだ異常がないなら、使ってみる価値はある。","ENG":"But if the ship's core is still intact, we could try to use it.","TWN":"不過如果艦船的核心還完整的話，倒可以拿來試試。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"함선에 쓰인 동력원으로 병기마를 다시 움직여 보자는 건가?","JPN":"艦船に使われた動力源で兵器馬を再び動かそうと言っているのか？","ENG":"Are you suggesting that we use the power generator in the ship to charge my Armored Horse?","TWN":"你是想用艦船上的動能來重新啟動戰馬嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"가능성은 있겠지만, 그런 이유로 이곳 사람들을 괜한 위험에 빠지게 만들고 싶지는 않아.","JPN":"可能性はありそうだが、そんな理由でここの人たちを無駄な危険に晒したくはないな。","ENG":"It's a possibility, but I don't wish to put the villagers in danger for that reason alone.","TWN":"雖然是可以嘗試看看，但我不希望因爲這樣，讓這裡的人無端陷入危險。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"함선까지는 나 혼자 동행할 거야.","JPN":"艦船までは私一人でついていく。","ENG":"So I'll be going with you to the ship.","TWN":"我自己陪你走到艦船那裡。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그리고 공짜로 도와 준다고 한 적도 없어. 거래를 하자는 거지.","JPN":"それに、ただで手伝うと言った覚えはないね。取引をしようってこと。","ENG":"And just so you know, I'm not helping you out for free. I'm offering you a deal.","TWN":"而且我也沒要你免費幫忙，就當作是交易。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"거래?","JPN":"取引？","ENG":"A deal?","TWN":"交易？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"우리 국경수비대에 정식대원으로 들어와. 그게 내 조건이야.","JPN":"国境守備隊の正式隊員になりなさい。それが条件。","ENG":"I want you to become an official member of our Border Guards. That's my one condition.","TWN":"正式加入我們國境護衛隊吧，那就是我的條件。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"정말 그걸로 괜찮은 건가? 자네는 몰라도 다른 대원들이 달갑지 않게 여길 텐데.","JPN":"本当にそれでいいのか？　君はともかく、他の隊員は不満に思うはずだ。","ENG":"Are you sure? I don't know about you, but I have a feeling that the others won't be so welcoming.","TWN":"真的沒關係嗎？你的隊員應該不會同意吧？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"난 이곳 남부 국경수비대의 결정권자로서 부대에 필요한 결정을 내린 거야.","JPN":"私はここ、南部国境守備隊の決定権者として部隊に必要な決定をしただけよ。","ENG":"I'm making a decision as the leader of the Southern Border Guards that is necessary for the troops.","TWN":"我身為南方國境護衛隊的決定者，做出對部隊必要的決定。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"제라드 큐리안이 여기 남는 편이, 우리에게 득이 된다고 판단했을 뿐이지.","JPN":"ジェラード・キュリアンがここにいた方が、プラスになると判断しただけ。","ENG":" I just think that Gerard Curian staying here is in our best interests.","TWN":"我只是認為傑瑞德· 庫里安留在這裡，對我們有利。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그리고…….","JPN":"それに……","ENG":"Furthermore...","TWN":"另外……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"무모한 짓이긴 했지만, 목숨을 내던지는 것만큼 확실한 자기증명도 없어.","JPN":"無茶ではあったけど、命を投げ打つことほど確かな自己証明もないし。","ENG":"Even though it was reckless, there's no better way for one to prove themselves than to risk their life for another.","TWN":"雖然很魯莽，但你已經用性命證明你自己。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"당신이 못마땅했던 대원들도 아이들을 구한 행동에는 틀림없이 마음이 움직였을 거야.","JPN":"あなたを快く思わなかった隊員も、子供たちを助けてくれたことにはきっと心が動いたはずよ。","ENG":"Even the members who despised you would have been moved by how you protected the children.","TWN":"相信那些不喜歡你的隊員，看到你救孩子的一片心意後，一定也會改變想法的。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그래서, 내 제안에 대한 대답은?","JPN":"それで、答えは？","ENG":"So, do we have a deal?","TWN":"説吧，你的回答是？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_CURIAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};